{{CSS|content=
.theme-fandomdesktop-dark,
.theme-fandomdesktop-light {
  --theme-page-background-color:#0b3d91;
  --theme-page-background-color--secondary:#1b5ac9;
  --theme-page-text-color:#111111;
  --theme-border-color:#245edb;
  --theme-link-color:#0047d5;
  --theme-community-header-color:#ffffff;
  --theme-sticky-nav-background-color:#003399;
}

#firstHeading { display:none; }

body {
  background:#0b3d91 !important;
  font-family:Tahoma,Verdana,Arial,sans-serif !important;
}

.page {
  background:
    linear-gradient(rgba(42,120,255,0.12),rgba(0,0,0,0.2)),
    radial-gradient(circle at top,#3a8cff,#0b3d91 70%) !important;
  border:3px solid #003399 !important;
  box-shadow:0 0 25px rgba(0,0,0,0.55), inset 0 0 45px rgba(255,255,255,0.16) !important;
  overflow:hidden;
}

@keyframes xp-bootfade {
  0% {opacity:1;visibility:visible;}
  82% {opacity:1;}
  100% {opacity:0;visibility:hidden;}
}

@keyframes xp-load {
  from {left:-35%;}
  to {left:100%;}
}

@keyframes xp-window-in {
  from {opacity:0;transform:translateY(20px) scale(.98);}
  to {opacity:1;transform:translateY(0) scale(1);}
}

@keyframes xp-flicker {
  0%,100% {opacity:1;}
  12% {opacity:.85;}
  13% {opacity:1;}
  60% {opacity:.92;}
  61% {opacity:1;}
  86% {opacity:.75;}
}

@keyframes xp-error-shake {
  0%,100% {transform:translate(0,0);}
  20% {transform:translate(-2px,1px);}
  40% {transform:translate(2px,-1px);}
  60% {transform:translate(-1px,-1px);}
  80% {transform:translate(1px,2px);}
}

@keyframes xp-scan {
  0% {top:-5%;}
  100% {top:105%;}
}

.xp-boot {
  position:fixed;
  inset:0;
  z-index:9999;
  background:#000;
  color:white;
  display:flex;
  align-items:center;
  justify-content:center;
  pointer-events:none;
  animation:xp-bootfade .8s ease 4.7s forwards;
}

.xp-boot-inner {
  text-align:center;
  width:430px;
}

.xp-logo {
  font-size:38px;
  font-weight:bold;
  text-shadow:0 0 12px #ffffff;
}

.xp-logo span {
  color:#43a047;
}

.xp-sub {
  margin-top:8px;
  font-size:14px;
  color:#cccccc;
}

.xp-loadbar {
  width:270px;
  height:18px;
  border:2px solid #777;
  margin:26px auto;
  overflow:hidden;
  background:#111;
  position:relative;
}

.xp-loadbar::after {
  content:"";
  position:absolute;
  top:2px;
  left:-35%;
  width:35%;
  height:12px;
  background:linear-gradient(90deg,#1d4ed8,#8fc7ff,#1d4ed8);
  animation:xp-load 1.1s linear infinite;
}

.xp-scanline {
  position:fixed;
  left:0;
  width:100%;
  height:3px;
  background:linear-gradient(90deg,transparent,rgba(255,255,255,.55),transparent);
  top:-5%;
  z-index:9997;
  pointer-events:none;
  animation:xp-scan 3s linear infinite;
}

.xp-desktop {
  max-width:1050px;
  margin:24px auto 70px;
  animation:xp-window-in .9s ease 4.9s both;
  position:relative;
}

.xp-window {
  border:2px solid #0055e5;
  border-radius:8px 8px 0 0;
  background:#ece9d8;
  box-shadow:6px 8px 22px rgba(0,0,0,.45);
  margin:18px 0;
  overflow:hidden;
}

.xp-titlebar {
  background:linear-gradient(#2f8cff,#0055e5 55%,#0039a6);
  color:white;
  height:32px;
  display:flex;
  align-items:center;
  justify-content:space-between;
  padding:0 8px 0 12px;
  font-weight:bold;
  text-shadow:1px 1px 0 #003399;
}

.xp-title {
  display:flex;
  gap:8px;
  align-items:center;
}

.xp-icon {
  width:17px;
  height:17px;
  background:linear-gradient(135deg,#fff,#9fd4ff);
  border:1px solid #003399;
}

.xp-buttons {
  display:flex;
  gap:4px;
}

.xp-btn {
  width:22px;
  height:22px;
  border:1px solid #fff;
  color:white;
  text-align:center;
  line-height:20px;
  font-weight:bold;
  border-radius:3px;
  box-shadow:inset 1px 1px 2px rgba(255,255,255,.6);
}

.xp-min,.xp-max {background:linear-gradient(#8bb9ff,#255edb);}
.xp-close {background:linear-gradient(#ff9a7a,#d62000);}

.xp-content {
  padding:20px;
  color:#111;
  background:#ece9d8;
  line-height:1.65;
}

.xp-warning {
  background:#fff8d7;
  border:1px solid #d6b400;
  padding:12px;
  margin:14px 0;
  box-shadow:inset 0 0 10px #fff;
}

.xp-danger {
  background:#2b0000;
  color:#ffd6d6;
  border:2px solid #b00000;
  padding:14px;
  margin:16px 0;
  box-shadow:inset 0 0 20px #000,0 0 12px rgba(120,0,0,.45);
}

.xp-error {
  background:#ffffff;
  border:2px solid #003399;
  box-shadow:4px 5px 12px rgba(0,0,0,.35);
  padding:14px;
  margin:18px auto;
  max-width:660px;
  animation:xp-error-shake .18s 3;
}

.xp-error-head {
  background:linear-gradient(#2f8cff,#0055e5);
  color:#fff;
  margin:-14px -14px 12px -14px;
  padding:6px 10px;
  font-weight:bold;
}

.xp-error-body {
  display:flex;
  gap:15px;
  align-items:flex-start;
}

.xp-error-symbol {
  width:38px;
  height:38px;
  border-radius:50%;
  background:#d60000;
  color:white;
  text-align:center;
  line-height:38px;
  font-size:30px;
  font-weight:bold;
}

.xp-img {
  border:4px solid #ffffff;
  outline:2px solid #9b9b9b;
  box-shadow:4px 6px 14px rgba(0,0,0,.45);
  margin:18px auto;
  background:#111;
  padding:6px;
  text-align:center;
}

.xp-img img {
  max-width:100%;
  filter:contrast(115%) saturate(90%) brightness(78%) hue-rotate(20deg);
}

.article-table {
  width:100%;
  border-collapse:collapse;
  background:white;
  color:#111;
  margin:14px 0;
}

.article-table th {
  background:#dbe8ff;
  color:#003399;
}

.article-table th,
.article-table td {
  border:1px solid #7da2ce;
  padding:10px;
}

h2 {
  color:#003399 !important;
  border-bottom:2px solid #7da2ce !important;
  font-family:Tahoma,Verdana,sans-serif !important;
}

a { color:#0047d5 !important; }

.xp-taskbar {
  position:fixed;
  bottom:0;
  left:0;
  width:100%;
  height:42px;
  background:linear-gradient(#245edb,#0c3fa5);
  z-index:9998;
  display:flex;
  align-items:center;
  box-shadow:0 -2px 8px rgba(0,0,0,.45);
}

.xp-start {
  height:42px;
  padding:0 18px;
  background:linear-gradient(#49b84a,#1e8f22);
  color:white;
  font-weight:bold;
  border-radius:0 12px 12px 0;
  display:flex;
  align-items:center;
  text-shadow:1px 1px 0 #065f08;
  font-style:italic;
  font-size:20px;
}

.xp-task {
  margin-left:10px;
  height:28px;
  min-width:190px;
  background:linear-gradient(#4f8fff,#1d5edb);
  border:1px solid #8bb9ff;
  color:white;
  display:flex;
  align-items:center;
  padding:0 10px;
  font-size:13px;
}

.xp-clock {
  margin-left:auto;
  color:white;
  padding:0 18px;
  font-size:13px;
  border-left:1px solid rgba(255,255,255,.3);
}

.xp-desktop::before {
  content:"";
  position:fixed;
  inset:0;
  pointer-events:none;
  background:repeating-linear-gradient(to bottom,rgba(255,255,255,.025) 0px,rgba(255,255,255,.025) 1px,transparent 2px,transparent 4px);
  z-index:9996;
  animation:xp-flicker 3s infinite;
}

@media only screen and (max-width:700px) {
  .xp-desktop {margin:10px auto 60px;}
  .xp-task {display:none;}
}
}}

{{CSS|content=
.theme-fandomdesktop-dark,
.theme-fandomdesktop-light {
  --theme-page-background-color:#020b0d;
  --theme-page-background-color--secondary:#061517;
  --theme-page-text-color:#d8f7f7;
  --theme-border-color:#4bbcc7;
  --theme-link-color:#9dfcff;
  --theme-community-header-color:#d9ffff;
  --theme-sticky-nav-background-color:#031012;
}

#firstHeading { display:none; }

body {
  background:#020b0d !important;
  font-family:Arial,Helvetica,sans-serif !important;
}

.page {
  background:
    linear-gradient(rgba(0,20,24,0.92),rgba(0,0,0,0.97)),
    repeating-linear-gradient(
      0deg,
      rgba(255,255,255,0.025) 0px,
      rgba(255,255,255,0.025) 1px,
      transparent 1px,
      transparent 5px
    ) !important;
  border:2px solid #4bbcc7 !important;
  box-shadow:0 0 28px rgba(50,220,230,0.32), inset 0 0 70px #000 !important;
}

@keyframes hotel-fade {
  from { opacity:0; transform:translateY(16px); }
  to { opacity:1; transform:translateY(0); }
}

@keyframes hotel-scan {
  0% { top:-5%; opacity:.22; }
  100% { top:105%; opacity:.04; }
}

@keyframes hotel-flicker {
  0%,100% { opacity:1; }
  18% { opacity:.88; }
  19% { opacity:1; }
  54% { opacity:.76; }
  55% { opacity:1; }
  82% { opacity:.92; }
}

@keyframes hotel-light {
  0%,100% { box-shadow:0 0 18px rgba(80,240,255,.24), inset 0 0 50px #000; }
  50% { box-shadow:0 0 34px rgba(80,240,255,.42), inset 0 0 70px #000; }
}

.hotel-page {
  max-width:980px;
  margin:30px auto;
  padding:30px;
  background:
    linear-gradient(rgba(4,22,25,.94),rgba(0,0,0,.98)),
    radial-gradient(circle at top,rgba(120,255,255,.16),transparent 35%);
  color:#d8f7f7;
  border:2px solid #7be9ef;
  border-radius:6px;
  box-shadow:0 0 28px rgba(80,240,255,.3), inset 0 0 65px #000;
  line-height:1.72;
  position:relative;
  animation:hotel-fade .8s ease both, hotel-light 7s infinite;
}

.hotel-page::before {
  content:"SAFE PLACE // NIGHT VIEW // VACANCY DETECTED";
  position:absolute;
  top:8px;
  right:12px;
  font-size:11px;
  letter-spacing:2px;
  color:rgba(180,255,255,.42);
}

.hotel-scanline {
  position:fixed;
  left:0;
  width:100%;
  height:3px;
  background:linear-gradient(90deg,transparent,rgba(180,255,255,.55),transparent);
  top:-5%;
  z-index:9998;
  pointer-events:none;
  animation:hotel-scan 3.8s linear infinite;
}

.hotel-title {
  text-align:center;
  padding:24px;
  margin-bottom:24px;
  border:1px solid #7be9ef;
  background:linear-gradient(90deg,rgba(0,60,70,.55),rgba(255,255,255,.08),rgba(0,60,70,.55));
  box-shadow:inset 0 0 30px #000;
}

.hotel-title-main {
  font-size:38px;
  letter-spacing:4px;
  color:#eaffff;
  text-shadow:0 0 10px #9dfcff;
}

.hotel-title-sub {
  font-size:18px;
  letter-spacing:3px;
  color:#a7dfe3;
}

.hotel-box {
  background:rgba(0,0,0,.42);
  border-left:5px solid #7be9ef;
  padding:16px;
  margin:18px 0;
  box-shadow:inset 0 0 25px #000;
}

.hotel-warning {
  background:rgba(30,20,0,.55);
  border:1px solid #f3d36b;
  color:#fff1b8;
  padding:14px;
  margin:18px 0;
  text-align:center;
  box-shadow:0 0 16px rgba(243,211,107,.25), inset 0 0 25px #000;
}

.hotel-img {
  text-align:center;
  background:#020607;
  border:1px solid #7be9ef;
  padding:10px;
  margin:22px 0;
  box-shadow:0 0 18px rgba(80,240,255,.28);
  animation:hotel-flicker 4s infinite;
}

.hotel-img img {
  max-width:100%;
  filter:contrast(112%) saturate(85%) brightness(82%) hue-rotate(8deg);
}

.hotel-caption {
  color:#a7dfe3;
  font-size:.9em;
  margin-top:8px;
  letter-spacing:1px;
}

.article-table {
  width:100%;
  border-collapse:collapse;
  background:#03090a;
  color:#d8f7f7;
}

.article-table th,
.article-table td {
  border:1px solid #4bbcc7;
  padding:10px;
}

.article-table th {
  background:#06272d;
  color:#eaffff;
}

h2 {
  color:#eaffff !important;
  border-bottom:1px solid #7be9ef !important;
  text-shadow:0 0 8px #5eefff;
}
}}
